1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const alive = new Set(cells.map(cellKey));
13	  const liveNeighborCount = ([x, y]: Cell): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;
15	  return cells.filter((cell) => {
16	    const n = liveNeighborCount(cell);
17	    return n === 2 || n === 3;
18	  });
19	}
20

