export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(cellKey));
  const liveNeighborCount = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;
  const survives = (cell: Cell): boolean => {
    const liveNeighbors = liveNeighborCount(cell);
    return liveNeighbors === 2 || liveNeighbors === 3;
  };
  return cells.filter(survives);
}

